const webhook = $('Webhook Chatwoot').first().json;
const convo = $json;

const body = webhook.body || webhook;
const conversation = body.conversation || {};
const account = body.account || {};
const inbox = body.inbox || {};
const sender = body.sender || body.contact || {};
const contact = convo.meta?.sender || convo.contact || sender || {};
const custom = convo.custom_attributes || conversation.custom_attributes || {};

const messageText = body.content || '';
const contactName = contact.name || sender.name || '';
const contactPhone = contact.phone_number || sender.phone_number || '';
const conversationId = conversation.id || convo.id || '';
const accountId = account.id || convo.account_id || '';

const leadSummary = custom.lead_summary || '';
const leadStatus = custom.STATUS || custom.status || 'LEAD_NOVO';
const lastIntent = custom.last_intent || '';
const juliaInitialized = String(custom.julia_initialized || 'false');

return [
  {
    json: {
      account_id: accountId,
      conversation_id: conversationId,
      inbox_id: inbox.id || convo.inbox_id || '',
      contact_id: contact.id || sender.id || '',
      contact_name: contactName,
      contact_phone: contactPhone,
      message_text: messageText,
      lead_summary: leadSummary,
      lead_status: leadStatus,
      last_intent: lastIntent,
      julia_initialized: juliaInitialized,
      raw_custom_attributes: custom
    }
  }
];

const dify = $json;
const ctx = $('Code Normalize Context').first().json;

const answerRaw = dify.answer || '';

let parsedStatus = null;
if (answerRaw.includes('#STATUS:HUMANO')) parsedStatus = 'HUMANO';
else if (answerRaw.includes('#STATUS:AGENDADO')) parsedStatus = 'AGENDADO';
else if (answerRaw.includes('#STATUS:AGUARDANDO_AGENDAMENTO')) parsedStatus = 'AGUARDANDO_AGENDAMENTO';
else if (answerRaw.includes('#STATUS:QUALIFICADO')) parsedStatus = 'QUALIFICADO';
else if (answerRaw.includes('#STATUS:EM_QUALIFICACAO')) parsedStatus = 'EM_QUALIFICACAO';
else if (answerRaw.includes('#STATUS:FORA_DO_PERFIL')) parsedStatus = 'FORA_DO_PERFIL';

const cleanAnswer = answerRaw
  .replace(/\s*#STATUS:HUMANO/g, '')
  .replace(/\s*#STATUS:AGENDADO/g, '')
  .replace(/\s*#STATUS:AGUARDANDO_AGENDAMENTO/g, '')
  .replace(/\s*#STATUS:QUALIFICADO/g, '')
  .replace(/\s*#STATUS:EM_QUALIFICACAO/g, '')
  .replace(/\s*#STATUS:FORA_DO_PERFIL/g, '')
  .trim();

const text = (ctx.message_text || '').toLowerCase();
let parsedIntent = ctx.last_intent || '';
if (text.includes('linkedin')) parsedIntent = 'LINKEDIN_ADS';
else if (text.includes('google')) parsedIntent = 'GOOGLE_ADS';
else if (text.includes('tráfego') || text.includes('trafego')) parsedIntent = 'TRAFEGO_PAGO';
else if (text.includes('automação') || text.includes('automacao') || text.includes('ia')) parsedIntent = 'AUTOMACAO_IA';
else if (text.includes('crm')) parsedIntent = 'CRM';
else if (text.includes('consultoria')) parsedIntent = 'CONSULTORIA';

const existingSummary = ctx.lead_summary || '';
const fields = {
  'Nome': '',
  'Empresa': '',
  'Nicho': '',
  'Serviço de interesse': '',
  'Objetivo': '',
  'Canal atual': '',
  'Vende por': '',
  'Equipe comercial': '',
  'Investimento': '',
  'Momento do lead': '',
  'Objeções': '',
  'Último contexto relevante': '',
  'Próxima etapa sugerida': ''
};

existingSummary.split('\n').forEach(line => {
  const idx = line.indexOf(':');
  if (idx > -1) {
    const key = line.slice(0, idx).trim();
    const value = line.slice(idx + 1).trim();
    if (Object.prototype.hasOwnProperty.call(fields, key)) {
      fields[key] = value;
    }
  }
});

if (ctx.contact_name && !fields['Nome']) fields['Nome'] = ctx.contact_name;
if (parsedIntent) fields['Serviço de interesse'] = parsedIntent;
if (ctx.message_text && ctx.message_text.length > 8) fields['Último contexto relevante'] = ctx.message_text;
if (parsedStatus === 'QUALIFICADO') fields['Próxima etapa sugerida'] = 'Agendamento com especialista';
if (parsedStatus === 'HUMANO') fields['Próxima etapa sugerida'] = 'Assumir manualmente';
if (!fields['Próxima etapa sugerida'] && ctx.lead_status === 'LEAD_NOVO') fields['Próxima etapa sugerida'] = 'Continuar qualificação';

const orderedKeys = [
  'Nome',
  'Empresa',
  'Nicho',
  'Serviço de interesse',
  'Objetivo',
  'Canal atual',
  'Vende por',
  'Equipe comercial',
  'Investimento',
  'Momento do lead',
  'Objeções',
  'Último contexto relevante',
  'Próxima etapa sugerida'
];

const updatedLeadSummary = orderedKeys
  .filter(key => fields[key] && String(fields[key]).trim() !== '')
  .map(key => `${key}: ${fields[key]}`)
  .join('\n');

let nextStatus = parsedStatus || ctx.lead_status || 'LEAD_NOVO';
if (!parsedStatus && nextStatus === 'LEAD_NOVO') {
  nextStatus = 'EM_QUALIFICACAO';
}

return [
  {
    json: {
      ...ctx,
      dify_conversation_id: dify.conversation_id || '',
      clean_answer: cleanAnswer,
      parsed_status: nextStatus,
      parsed_intent: parsedIntent,
      updated_lead_summary: updatedLeadSummary,
      julia_initialized_next: 'true'
    }
  }
];
